diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..48d738a680b6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5155,6 +5155,119 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
     }
   }

+  // icmp (sdiv X, C), X where C > 1
+  // For signed division: X / C < X  iff  X > 0 (when C > 1)
+  //                     X / C > X  iff  X < 0 (when C > 1)
+  //                     X / C == X iff  X == 0 (when C > 1)
+  const APInt *DivisorC;
+  if (BO0 && match(BO0, m_SDiv(m_Value(X), m_APInt(DivisorC))) &&
+      Op1 == X && DivisorC->isStrictlyPositive() && DivisorC->ugt(1)) {
+    // We have: icmp pred (sdiv X, C), X where C > 1
+    switch (Pred) {
+    case ICmpInst::ICMP_SLT:
+      return new ICmpInst(ICmpInst::ICMP_SGT, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SGT:
+      return new ICmpInst(ICmpInst::ICMP_SLT, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SLE:
+      return new ICmpInst(ICmpInst::ICMP_SGE, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SGE:
+      return new ICmpInst(ICmpInst::ICMP_SLE, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_EQ:
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_NE:
+      return new ICmpInst(ICmpInst::ICMP_NE, X, Constant::getNullValue(X->getType()));
+    default:
+      break;
+    }
+  }
+
+  // icmp (udiv X, C), X where C > 1
+  // For unsigned division: X / C < X  iff  X > 0 (when C > 1)
+  //                      X / C == X iff  X == 0 (when C > 1)
+  if (BO0 && match(BO0, m_UDiv(m_Value(X), m_APInt(DivisorC))) &&
+      Op1 == X && DivisorC->ugt(1)) {
+    // We have: icmp pred (udiv X, C), X where C > 1
+    switch (Pred) {
+    case ICmpInst::ICMP_ULT:
+      return new ICmpInst(ICmpInst::ICMP_NE, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_UGT:
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_ULE:
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_UGE:
+      return new ICmpInst(ICmpInst::ICMP_NE, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SLT:
+      return new ICmpInst(ICmpInst::ICMP_SGT, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SGT:
+      return new ICmpInst(ICmpInst::ICMP_SLT, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SLE:
+      return new ICmpInst(ICmpInst::ICMP_SGE, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SGE:
+      return new ICmpInst(ICmpInst::ICMP_SLE, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_EQ:
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_NE:
+      return new ICmpInst(ICmpInst::ICMP_NE, X, Constant::getNullValue(X->getType()));
+    default:
+      break;
+    }
+  }
+
+  // icmp (lshr X, C), X where C > 0
+  // For logical shift right: X >> C < X  iff  X > 0 (when C > 0)
+  //                          X >> C == X iff  X == 0 (when C > 0)
+  const APInt *ShiftC;
+  if (BO0 && match(BO0, m_LShr(m_Value(X), m_APInt(ShiftC))) &&
+      Op1 == X && ShiftC->ugt(0)) {
+    // We have: icmp pred (lshr X, C), X where C > 0
+    switch (Pred) {
+    case ICmpInst::ICMP_ULT:
+      return new ICmpInst(ICmpInst::ICMP_NE, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_UGT:
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_ULE:
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_UGE:
+      return new ICmpInst(ICmpInst::ICMP_NE, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SLT:
+      return new ICmpInst(ICmpInst::ICMP_SGT, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SGT:
+      return new ICmpInst(ICmpInst::ICMP_SLT, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SLE:
+      return new ICmpInst(ICmpInst::ICMP_SGE, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SGE:
+      return new ICmpInst(ICmpInst::ICMP_SLE, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_EQ:
+      return new ICmpInst(ICmpInst::ICMP_EQ, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_NE:
+      return new ICmpInst(ICmpInst::ICMP_NE, X, Constant::getNullValue(X->getType()));
+    default:
+      break;
+    }
+  }
+
+  // icmp (ashr X, C), X where C > 0
+  // For arithmetic shift right: X >> C < X  iff  X > 0 (when C > 0)
+  //                            X >> C > X  iff  X < -1 (when C > 0)
+  //                            X >> C >= X iff  X < 1 (when C > 0)
+  // Note: We don't handle SLE because:
+  //   (ashr X, C) <= X is true for X >= -1, which is not a simple comparison with 0
+  if (BO0 && match(BO0, m_AShr(m_Value(X), m_APInt(ShiftC))) &&
+      Op1 == X && ShiftC->ugt(0)) {
+    // We have: icmp pred (ashr X, C), X where C > 0
+    switch (Pred) {
+    case ICmpInst::ICMP_SLT:
+      return new ICmpInst(ICmpInst::ICMP_SGT, X, Constant::getNullValue(X->getType()));
+    case ICmpInst::ICMP_SGT:
+      return new ICmpInst(ICmpInst::ICMP_SLT, X, Constant::getAllOnesValue(X->getType()));
+    case ICmpInst::ICMP_SGE:
+      return new ICmpInst(ICmpInst::ICMP_SLT, X, ConstantInt::get(X->getType(), 1));
+    default:
+      break;
+    }
+  }
+
+
   if (BO0 && BO1 && BO0->getOpcode() == BO1->getOpcode() &&
       (BO0->hasOneUse() || BO1->hasOneUse()) &&
       BO0->getOperand(1) == BO1->getOperand(1)) {

